// frontend/src/pages/Users.jsx
import { useEffect, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;

function normalizeList(d) {
    return Array.isArray(d)
        ? { list: d, pages: 1 }
        : { list: d?.content || [], pages: d?.totalPages || 1 };
}

const ROLES = ["ADMIN", "SALES", "ACCOUNTANT"];
const STATUSES = ["ACTIVE", "INACTIVE"];

export default function Users() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState({
        username: "",
        fullName: "",
        email: "",
        phone: "",
        roleName: "SALES",
        active: "ACTIVE",
        password: "",
        confirmPassword: "",
    });

    useEffect(() => {
        load();
    }, [page]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/users", {
                params: { page, size: PAGE_SIZE, sort: "id,desc" },
            });
            const { list, pages } = normalizeList(data);
            setRows(
                list.map((u) => ({
                    id: u.id,
                    username: u.username,
                    fullName: u.fullName,
                    email: u.email,
                    phone: u.phone,
                    roleName: u.role,
                    active: u.active ? "ACTIVE" : "INACTIVE",
                }))
            );
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({
            username: "",
            fullName: "",
            email: "",
            phone: "",
            roleName: "SALES",
            active: "ACTIVE",
            password: "",
            confirmPassword: "",
        });
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            ...row,
            active: row.active,
        });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();

        // map UI -> backend
        const roleName = form.role;                     // UI đang lưu ở form.role
        const active   = form.status === "ACTIVE";      // UI -> boolean
        const phone    = form.phone?.trim() || null;

        try {
            if (!editing) {
                // ====== B1: REGISTER (chỉ gửi đúng các field được phép) ======
                if (!form.password || form.password.length < 4) {
                    alert("Vui lòng nhập mật khẩu (>=4 ký tự)");
                    return;
                }
                const regRes = await api.post("/api/users", {
                    username: form.username,
                    fullName: form.fullName,   // hoặc form.name tuỳ bạn đang đặt
                    email: form.email,
                    password: form.password,
                });

                // Lấy id user vừa tạo
                let newId =
                    regRes?.data?.id ??
                    regRes?.data?.user?.id ??
                    regRes?.data?.data?.id ??
                    null;

                // fallback nếu backend không trả id: tìm theo username (ít nhất cũng tìm trong trang đầu)
                if (!newId) {
                    const listRes = await api.get("/api/users", { params: { page: 0, size: 10, sort: "id,desc" } });
                    const found = (Array.isArray(listRes.data) ? listRes.data : listRes.data.content || [])
                        .find(u => (u.username || u.name) === form.username);
                    newId = found?.id;
                }

                if (!newId) {
                    alert("Không lấy được ID người dùng mới tạo.");
                    return;
                }

                // ====== B2: UPDATE các field chỉ cho phép ở UserUpdateRequest ======
                await api.put(`/api/users/${newId}`, {
                    fullName: form.fullName,
                    email: form.email,
                    phone,
                    roleName,
                    active,
                });

            } else {
                // ====== EDIT: chỉ gửi đúng UserUpdateRequest ======
                await api.put(`/api/users/${editing.id}`, {
                    fullName: form.fullName,
                    email: form.email,
                    phone,
                    roleName,
                    active,
                });
            }

            setShow(false);
            await load(); // reload danh sách
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                JSON.stringify(err?.response?.data) ||
                "Lưu người dùng thất bại";
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá người dùng ${row.username}?`)) return;
        try {
            await api.delete(`/api/users/${row.id}`);
            await load();
        } catch (err) {
            alert(err?.response?.data?.message || "Xoá người dùng thất bại");
        }
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
                    <p className="text-sm text-slate-500">
                        Quản trị viên có thể quản lý người dùng
                    </p>
                </div>
                <button
                    onClick={openCreate}
                    className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                >
                    Thêm người dùng
                </button>
            </div>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên đăng nhập</th>
                            <th className="px-4 py-3 text-left">Họ tên</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Vai trò</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((u) => (
                                <tr key={u.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{u.username}</td>
                                    <td className="px-4 py-3">{u.fullName}</td>
                                    <td className="px-4 py-3">{u.email}</td>
                                    <td className="px-4 py-3">{u.phone || "-"}</td>
                                    <td className="px-4 py-3">{u.roleName}</td>
                                    <td className="px-4 py-3">
                      <span
                          className={
                              "px-2 py-0.5 rounded-full text-xs " +
                              (u.active === "ACTIVE"
                                  ? "bg-emerald-100 text-emerald-700"
                                  : "bg-slate-100 text-slate-700")
                          }
                      >
                        {u.active}
                      </span>
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="inline-flex gap-2">
                                            <button
                                                onClick={() => openEdit(u)}
                                                className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                            >
                                                Sửa
                                            </button>
                                            <button
                                                onClick={() => remove(u)}
                                                className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                            >
                                                Xóa
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">
                    Trang {page + 1}/{totalPages}
                </div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => p + 1)}
                    disabled={page + 1 >= totalPages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-2xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">
                                {editing ? "Sửa người dùng" : "Thêm người dùng"}
                            </div>
                            <button
                                className="text-slate-500 hover:text-slate-700"
                                onClick={() => setShow(false)}
                            >
                                Đóng
                            </button>
                        </div>

                        <form
                            onSubmit={save}
                            className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4"
                        >
                            {!editing && (
                                <div>
                                    <label className="text-sm text-slate-600">Tên đăng nhập</label>
                                    <input
                                        required
                                        value={form.username}
                                        onChange={(e) =>
                                            setForm((f) => ({ ...f, username: e.target.value }))
                                        }
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>
                            )}

                            <div>
                                <label className="text-sm text-slate-600">Họ tên</label>
                                <input
                                    required
                                    maxLength={100}
                                    value={form.fullName}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, fullName: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Email</label>
                                <input
                                    type="email"
                                    maxLength={150}
                                    value={form.email}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, email: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Điện thoại</label>
                                <input
                                    maxLength={20}
                                    value={form.phone}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, phone: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Vai trò</label>
                                <select
                                    value={form.roleName}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, roleName: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {ROLES.map((r) => (
                                        <option key={r}>{r}</option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select
                                    value={form.active}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, active: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {STATUSES.map((s) => (
                                        <option key={s}>{s}</option>
                                    ))}
                                </select>
                            </div>

                            {/* Password chỉ hiện khi thêm mới */}
                            {!editing && (
                                <>
                                    <div className="md:col-span-2">
                                        <label className="text-sm text-slate-600">Mật khẩu</label>
                                        <input
                                            required
                                            type="password"
                                            value={form.password}
                                            onChange={(e) =>
                                                setForm((f) => ({ ...f, password: e.target.value }))
                                            }
                                            className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                        />
                                    </div>
                                    <div className="md:col-span-2">
                                        <label className="text-sm text-slate-600">
                                            Xác nhận mật khẩu
                                        </label>
                                        <input
                                            required
                                            type="password"
                                            value={form.confirmPassword}
                                            onChange={(e) =>
                                                setForm((f) => ({
                                                    ...f,
                                                    confirmPassword: e.target.value,
                                                }))
                                            }
                                            className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                        />
                                    </div>
                                </>
                            )}

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                >
                                    Hủy
                                </button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
